fn solve(s: String) -> i64 {
    let n = s.len();
    let s_bytes = s.as_bytes();
    let mut prefix_L = vec![0i64; n + 1];
    for i in 0..n {
        prefix_L[i + 1] = prefix_L[i] + if s_bytes[i] == b'L' { 1 } else { 0 };
    }

    let mut suffix_t = vec![0i64; n + 1];
    for i in (0..n).rev() {
        suffix_t[i] = suffix_t[i + 1] + if s_bytes[i] == b'T' { 1 } else { 0 };
    }

    let mut base: i64 = 0;
    for j in 0..n {
        if s_bytes[j] == b'C' {
            base += prefix_L[j] * suffix_t[j + 1];
        }
    }

    let mut arr_L = vec![0i64; n + 1];
    for i in (0..n).rev() {
        arr_L[i] = arr_L[i + 1];
        if s_bytes[i] == b'C' {
            arr_L[i] += suffix_t[i + 1];
        }
    }

    let mut prefix_C_sum = vec![0i64; n + 1];
    for i in 0..n {
        prefix_C_sum[i + 1] = prefix_C_sum[i];
        if s_bytes[i] == b'C' {
            prefix_C_sum[i + 1] += prefix_L[i];
        }
    }

    let mut ans = base;
    for k in 0..=n {
        let candidate_c = prefix_L[k] * suffix_t[k];
        let candidate_t = prefix_C_sum[k];
        let candidate_l = arr_L[k];
        let candidate_best = candidate_l.max(candidate_c).max(candidate_t);
        let total_candidate = base + candidate_best;
        if total_candidate > ans {
            ans = total_candidate;
        }
    }

    ans
}
```

