fn solve(s: String) -> i64 {
    let n = s.len();
    let s_chars: Vec<char> = s.chars().collect();

    let (mut countL, mut countLC, mut base) = (0_i64, 0_i64, 0_i64);
    for &c in &s_chars {
        if c == 'L' {
            countL += 1;
        } else if c == 'C' {
            countLC += countL;
        } else if c == 'T' {
            base += countLC;
        }
    }

    let mut prefix_L = vec![0_i64; n+1];
    let mut prefix_LC = vec![0_i64; n+1];
    for i in 0..n {
        prefix_L[i+1] = prefix_L[i] + if s_chars[i] == 'L' { 1 } else { 0 };
        if s_chars[i] == 'C' {
            prefix_LC[i+1] = prefix_LC[i] + prefix_L[i];
        } else {
            prefix_LC[i+1] = prefix_LC[i];
        }
    }

    let mut suffix_T = vec![0_i64; n+2];
    let mut suffix_CT = vec![0_i64; n+2];
    suffix_T[n] = 0;
    suffix_CT[n] = 0;
    for i in (0..n).rev() {
        suffix_T[i] = suffix_T[i+1] + if s_chars[i] == 'T' { 1 } else { 0 };
        if s_chars[i] == 'C' {
            suffix_CT[i] = suffix_CT[i+1] + suffix_T[i+1];
        } else {
            suffix_CT[i] = suffix_CT[i+1];
        }
    }

    let mut best = base;
    for i in 0..=n {
        let candidate_l = suffix_CT[i];
        let candidate_c = prefix_L[i] * suffix_T[i];
        let candidate_t = prefix_LC[i];
        let max_candidate = candidate_l.max(candidate_c).max(candidate_t);
        let total = base + max_candidate;
        if total > best {
            best = total;
        }
    }

    best
}
```

